import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";

const LoginPage = () => {
  const [formData, setFormData] = useState({ username: "", password: "" });
  const [error, setError] = useState("");
  const navigate = useNavigate();
  const apiUrl = process.env.REACT_APP_API_URL || "http://localhost:8080";

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch(`${apiUrl}/auth/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      });

      if (response.ok) {
        const user = await response.json();
        // Guardamos en el navegador para que no se borre al refrescar
        localStorage.setItem("loggedUser", JSON.stringify(user));
        // Redirigimos a la página de tareas
        navigate("/tareas");
      } else {
        setError("Usuario o contraseña incorrectos");
      }
    } catch (err) {
      setError("No se pudo conectar con el servidor");
    }
  };

  return (
    <div style={{ textAlign: "center", marginTop: "50px" }}>
      <h1>Bienvenido a To-Do List</h1>
      <div className="loginContenedor" style={{ display: "inline-block", textAlign: "left" }}>
        <h2>Iniciar Sesión</h2>
        <form onSubmit={handleSubmit} className="LoginInput">
          <input
            type="text"
            name="username"
            placeholder="Usuario"
            onChange={handleChange}
            required
            style={{ display: "block", marginBottom: "10px", width: "100%" }}
          />
          <input
            type="password"
            name="password"
            placeholder="Contraseña"
            onChange={handleChange}
            required
            style={{ display: "block", marginBottom: "10px", width: "100%" }}
          />
          <button type="submit" style={{ width: "100%" }}>Entrar</button>
        </form>
        {error && <p style={{ color: "red" }}>{error}</p>}
      </div>
      <div style={{ marginTop: "20px" }}>
        <Link to="/register">¿No tienes cuenta? Regístrate</Link>
      </div>
    </div>
  );
};

export default LoginPage;
